import asyncio

class EchoProtocol(asyncio.Protocol):

    def connection_made(self, transport: asyncio.Transport) -> None:
        peer = transport.get_extra_info("peername")
        print(f"Connection from {peer}")
        self.transport = transport   # store for later writes

    def data_received(self, data: bytes) -> None:
        message = data.decode()
        print(f"Received: {message!r}")
        self.transport.write(data)   # echo back

    def eof_received(self) -> bool | None:
        print("Client sent EOF")
        return False  # False means close the connection

    def connection_lost(self, exc: Exception | None) -> None:
        if exc:
            print(f"Connection error: {exc}")
        else:
            print("Connection closed cleanly")

class FlowAwareProtocol(asyncio.Protocol):

    def __init__(self):
        self.transport = None
        self._paused = False
        self._drain_waiters: list[asyncio.Future] = []

    def connection_made(self, transport):
        self.transport = transport

    def data_received(self, data):
        # Process incoming data
        pass

    def pause_writing(self):
        self._paused = True

    def resume_writing(self):
        self._paused = False
        # Notify anyone waiting for the buffer to drain
        for waiter in self._drain_waiters:
            if not waiter.done():
                waiter.set_result(None)
        self._drain_waiters.clear()

    async def drain(self):
        """Await this after write() to respect back-pressure."""
        if self._paused:
            loop = asyncio.get_running_loop()
            fut = loop.create_future()
            self._drain_waiters.append(fut)
            await fut

class UDPEchoProtocol(asyncio.DatagramProtocol):

    def connection_made(self, transport: asyncio.DatagramTransport) -> None:
        self.transport = transport

    def datagram_received(self, data: bytes, addr: tuple) -> None:
        print(f"Received {data!r} from {addr}")
        self.transport.sendto(data, addr)   # echo back to sender

    def error_received(self, exc: Exception) -> None:
        print(f"UDP error: {exc}")

    def connection_lost(self, exc: Exception | None) -> None:
        print("UDP socket closed")


async def main():
    loop = asyncio.get_running_loop()
    transport, protocol = await loop.create_datagram_endpoint(
        UDPEchoProtocol,
        local_addr=("127.0.0.1", 9999),
    )
    try:
        await asyncio.sleep(30)
    finally:
        transport.close()

asyncio.run(main())

import asyncio

class LineProtocol(asyncio.Protocol):
    """A base class for line-oriented text protocols."""

    DELIMITER = b"\r\n"
    MAX_LINE_LENGTH = 8192

    def __init__(self):
        self.transport: asyncio.Transport | None = None
        self._buffer = bytearray()

    def connection_made(self, transport: asyncio.Transport) -> None:
        self.transport = transport

    def data_received(self, data: bytes) -> None:
        self._buffer.extend(data)
        while self.DELIMITER in self._buffer:
            line, _, self._buffer = self._buffer.partition(self.DELIMITER)
            if len(line) > self.MAX_LINE_LENGTH:
                self.transport.write(b"ERROR line too long\r\n")
                self.transport.close()
                return
            self.line_received(line.decode("utf-8", errors="replace"))

    def line_received(self, line: str) -> None:
        """Override in subclass to handle a complete line."""
        raise NotImplementedError

    def send_line(self, line: str) -> None:
        self.transport.write(line.encode("utf-8") + self.DELIMITER)

    def connection_lost(self, exc: Exception | None) -> None:
        self._buffer.clear()


class EchoLineProtocol(LineProtocol):
    def line_received(self, line: str) -> None:
        if line.strip().upper() == "QUIT":
            self.send_line("BYE")
            self.transport.close()
        else:
            self.send_line(f"ECHO: {line}")


async def main():
    loop = asyncio.get_running_loop()
    server = await loop.create_server(EchoLineProtocol, "127.0.0.1", 8080)
    async with server:
        await server.serve_forever()

asyncio.run(main())

def connection_made(self, transport):
    self.transport = transport
    self._reset_timeout()

def data_received(self, data):
    self._reset_timeout()
    # ... process data

def _reset_timeout(self):
    if hasattr(self, "_timeout_handle"):
        self._timeout_handle.cancel()
    loop = asyncio.get_running_loop()
    self._timeout_handle = loop.call_later(30, self._on_timeout)

def _on_timeout(self):
    if self.transport:
        self.transport.close()

MAX_CONNECTIONS = 10_000
active_connections = 0

class BoundedProtocol(asyncio.Protocol):
    def connection_made(self, transport):
        global active_connections
        if active_connections >= MAX_CONNECTIONS:
            transport.abort()
            return
        active_connections += 1
        self.transport = transport

    def connection_lost(self, exc):
        global active_connections
        active_connections -= 1
